import { createEnv } from "@t3-oss/env-nextjs";
import { vercel } from "@t3-oss/env-nextjs/presets-zod";
import { env as emailEnv } from "@vendor/email/env";
import { env as inngestEnv } from "@vendor/inngest/env";
import { env as nextEnv } from "@vendor/next/env";
import { betterstackEnv } from "@vendor/observability/betterstack-env";
import { sentryEnv } from "@vendor/observability/sentry-env";
import { env as securityEnv } from "@vendor/security/env";
import { z } from "zod";
// NOTE: Avoid importing TS files from vendor packages at config-load time.
// Mirror the minimal BaseHub env schema here to prevent Node resolution issues.

export const env = createEnv({
  extends: [
    vercel(),
    betterstackEnv,
    sentryEnv,
    securityEnv,
    emailEnv,
    inngestEnv,
    nextEnv,
  ],
  shared: {
    NODE_ENV: z
      .enum(["development", "production", "test"])
      .default("development"),
  },
  /**
   * Specify your server-side environment variables schema here.
   * This way you can ensure the app isn't built with invalid env vars.
   */
  server: {
    HEALTH_CHECK_AUTH_TOKEN: z.string().min(32).optional(),
    PORT: z.coerce.number().positive().optional().default(3000),
    BASEHUB_TOKEN: z.string().min(1).startsWith("bshb_pk_"),
    BASEHUB_CHANGELOG_TOKEN: z
      .string()
      .min(1)
      .startsWith("bshb_pk_")
      .optional(),
    MXBAI_API_KEY: z.string().min(1),
    MXBAI_STORE_ID: z.string().min(1),
  },

  /**
   * Specify your client-side environment variables schema here.
   * For them to be exposed to the client, prefix them with `NEXT_PUBLIC_`.
   */
  client: {
    NEXT_PUBLIC_VERCEL_ENV: z
      .enum(["development", "preview", "production"])
      .default("development"),
  },
  /**
   * Destructure all variables from `process.env` to make sure they aren't tree-shaken away.
   */
  experimental__runtimeEnv: {
    NODE_ENV: process.env.NODE_ENV,
    NEXT_PUBLIC_VERCEL_ENV: process.env.NEXT_PUBLIC_VERCEL_ENV,
  },
  // Server variables don't need to be in experimental__runtimeEnv
  skipValidation:
    !!process.env.SKIP_ENV_VALIDATION ||
    process.env.npm_lifecycle_event === "lint",

  /**
   * Makes it so that empty strings are treated as undefined. `SOME_VAR: z.string()` and
   * `SOME_VAR=''` will throw an error.
   */
  emptyStringAsUndefined: true,
});

import { withBetterStack } from "@logtail/next";
import withBundleAnalyzer from "@next/bundle-analyzer";
import { withSentryConfig } from "@sentry/nextjs";
import { baseConfig, sentryOptions } from "@vendor/next/config";
import { withMicrofrontends } from "@vercel/microfrontends/next/config";
import withVercelToolbar from "@vercel/toolbar/plugins/next";
import { createMDX } from "fumadocs-mdx/next";
import merge from "lodash.merge";
import type { NextConfig } from "next";

import { env } from "~/env";

const wwwConfig: NextConfig = merge({}, baseConfig, {
  images: {
    qualities: [10, 75, 100],
  },

  async redirects() {
    return [
      {
        source: "/docs",
        destination: "/docs/get-started/overview",
        permanent: true,
      },
      {
        source: "/docs/api",
        destination: "/docs/api-reference/getting-started/overview",
        permanent: true,
      },
      {
        source: "/docs/api-reference",
        destination: "/docs/api-reference/getting-started/overview",
        permanent: true,
      },
      {
        source: "/docs/get-started",
        destination: "/docs/get-started/overview",
        permanent: true,
      },
      {
        source: "/docs/connectors",
        destination: "/docs/connectors/github",
        permanent: true,
      },
      {
        source: "/docs/integrate",
        destination: "/docs/integrate/sdk",
        permanent: true,
      },
      {
        source: "/docs/api-reference/getting-started",
        destination: "/docs/api-reference/getting-started/overview",
        permanent: true,
      },
      {
        source: "/docs/api-reference/sdks-tools",
        destination: "/docs/api-reference/sdks-tools/typescript-sdk",
        permanent: true,
      },
    ];
  },

  transpilePackages: [
    "@repo/og",
    "@repo/ui",
    "@vendor/aeo",
    "@vendor/analytics",
    "@vendor/email",
    "@vendor/inngest",
    "@vendor/next",
    "@vendor/observability",
    "@vendor/security",
    "@vendor/seo",
  ],

  typedRoutes: true,

  experimental: {
    optimizePackageImports: [
      "framer-motion",
      "date-fns",
      "class-variance-authority",
      "lucide-react",
    ],
  },
} satisfies NextConfig);

let config: NextConfig = withBetterStack(withVercelToolbar()(wwwConfig));

if (env.VERCEL) {
  config = withSentryConfig(config, sentryOptions) as NextConfig;
}

if (process.env.ANALYZE === "true") {
  config = withBundleAnalyzer()(config) as NextConfig;
}

const withMDX = createMDX({
  configPath: "source.config.ts",
});

export default withMicrofrontends(withMDX(config), {
  debug: process.env.NODE_ENV === "development",
});

